// Config
const TZ = 'America/Fortaleza';
const operadores = items.map(i => i.json);

// Data/horário de referência (vem de outro workflow)
// Pode ser "2025-12-13T00:00:00.000-03:00" ou null
const dataTexto = (() => {
  try { return $('data para verificar os horarios').first().json.data; }
  catch (e) { return null; }
})();

// targetDate (YYYY-MM-DD) — se vier dataTexto usa ela, senão usa hoje no TZ
const eventDate = dataTexto ? String(dataTexto).split('T')[0] : null;
const todayTZ = new Date().toLocaleDateString('en-CA', { timeZone: TZ });
const targetDate = eventDate || todayTZ;

// Hora/minuto ATUAL em America/Fortaleza (sempre agora, nunca da dataTexto)
const [horaAtual, minutoAtual] = (() => {
  const partsNow = new Date().toLocaleTimeString('en-GB', { timeZone: TZ, hour12: false }).split(':');
  return [Number(partsNow[0]), Number(partsNow[1])];
})();

// limite mínimo: agora + 45 minutos — só se targetDate for hoje
const limiteMin = (targetDate === todayTZ)
  ? (horaAtual * 60 + minutoAtual + 45)
  : -Infinity;

// Pega eventos do Google Calendar passado pelo Aggregate
let rawGoogle = [];
try {
  rawGoogle = $('Aggregate').first().json.data;
} catch (e) {
  rawGoogle = [];
}

// Normaliza flatten: rawGoogle pode ser [ { data: [ ...events ] } ] ou já ser array de events
let googleEvents = [];
if (Array.isArray(rawGoogle) && rawGoogle.length > 0 && rawGoogle[0] && Array.isArray(rawGoogle[0].data)) {
  googleEvents = rawGoogle.flatMap(obj => obj.data || []);
} else if (Array.isArray(rawGoogle)) {
  googleEvents = rawGoogle;
} else {
  googleEvents = [];
}

// util: parse "HH:MM" -> minutos desde 00:00
function parseHHMMToMin(s) {
  if (!s || typeof s !== 'string') return NaN;
  const parts = s.trim().split(':').map(p => Number(p));
  if (parts.length < 2 || Number.isNaN(parts[0]) || Number.isNaN(parts[1])) return NaN;
  return parts[0] * 60 + parts[1];
}

// util: extrai "YYYY-MM-DD" de uma dateTime string considerando TZ
function dateStringInTZ(dateTimeStr) {
  // dateTimeStr pode ser "2025-12-13" (all-day) ou "2025-12-13T08:00:00-03:00"
  const d = new Date(dateTimeStr);
  return d.toLocaleDateString('en-CA', { timeZone: TZ });
}

// util: extrai minutos desde 00:00 no TZ para uma dateTime string
function minutesInDayFromDateTime(dateTimeStr) {
  // se date-only (YYYY-MM-DD) -> tratar como full-day start 00:00
  if (!dateTimeStr) return NaN;
  // dateTimeStr might be "2025-12-13" or ISO with offset
  const d = new Date(dateTimeStr);
  const parts = d.toLocaleTimeString('en-GB', { timeZone: TZ, hour12: false }).split(':');
  return Number(parts[0]) * 60 + Number(parts[1]);
}

// Constrói um map de busy intervals por email para a targetDate
// cada intervalo: { startMin, endMin }
const busyByEmail = {};

// percorre googleEvents, filtra por evento na targetDate e popula busyByEmail
for (const ev of googleEvents) {
  if (!ev) continue;

  // ignore cancelled
  if (ev.status === 'cancelled') continue;

  // if event explicitly transparent -> skip (não bloqueia)
  if (ev.transparency && String(ev.transparency).toLowerCase() === 'transparent') continue;

  // Start/End podem ser dateTime ou date (all-day)
  const startRaw = ev.start ? (ev.start.dateTime || ev.start.date) : null;
  const endRaw   = ev.end   ? (ev.end.dateTime   || ev.end.date)   : null;
  if (!startRaw || !endRaw) continue;

  // Determina data do evento no TZ; se for diferente do targetDate pula
  const evDate = dateStringInTZ(startRaw);
  if (evDate !== targetDate) continue;

  // Se for all-day (start.date presente), considerar como ocupando o dia inteiro
  // Observação: O Google normalmente usa end.date sendo o dia seguinte para all-day events.
  // Para segurança, se a string vier no formato YYYY-MM-DD, consideramos full-day bloqueado.
  let startMin, endMin;
  if (/^\d{4}-\d{2}-\d{2}$/.test(startRaw) && /^\d{4}-\d{2}-\d{2}$/.test(endRaw)) {
    // marcar full day (00:00 - 24:00)
    startMin = 0;
    endMin = 24 * 60;
  } else {
    startMin = minutesInDayFromDateTime(startRaw);
    endMin = minutesInDayFromDateTime(endRaw);
    // segurança: se endMin==startMin (evento de 0min) ou endMin < startMin -> tratar como full day
    if (Number.isNaN(startMin) || Number.isNaN(endMin) || endMin <= startMin) {
      startMin = 0;
      endMin = 24 * 60;
    }
  }

  // Decide quem marcar: se houver attendees -> marcar todos; senão marcar creator
  if (Array.isArray(ev.attendees) && ev.attendees.length > 0) {
    for (const at of ev.attendees) {
      if (!at || !at.email) continue;
      const email = String(at.email).toLowerCase();
      busyByEmail[email] = busyByEmail[email] || [];
      busyByEmail[email].push({ startMin, endMin });
    }
  } else if (ev.creator && ev.creator.email) {
    const email = String(ev.creator.email).toLowerCase();
    busyByEmail[email] = busyByEmail[email] || [];
    busyByEmail[email].push({ startMin, endMin });
  }
  // IGNORA organizer como pedido
}

// Função para checar se um slot [s, e) colide com alguma busy interval
function collidesWithBusy(emailLower, slotStart, slotEnd) {
  const busys = busyByEmail[emailLower];
  if (!busys) return false;
  for (const b of busys) {
    // overlap if b.start < slotEnd && b.end > slotStart
    if (b.startMin < slotEnd && b.endMin > slotStart) return true;
  }
  return false;
}

// Geração dos resultados
const resultado = [];

for (const op of operadores) {
  const nome = op["NOME"];
  const emailRaw = op["EMAIL"];
  if (!emailRaw) continue;
  const email = String(emailRaw).toLowerCase();

  // parse horários do operador (strings "HH:MM")
  const inicioHorarioMin = parseHHMMToMin(String(op["HORARIO DE INICIO"] || '').trim());
  const fimHorarioMin    = parseHHMMToMin(String(op["HORARIO FIM"] || '').trim());
  const inicioAlmMin     = parseHHMMToMin(String(op["INÍCIO ALMOÇO"] || op["INICIO ALMOÇO"] || '').trim());
  const fimAlmMin        = parseHHMMToMin(String(op["FIM ALMOÇO"]   || op["FIM ALMOCO"]   || '').trim());
  const horaOuroInicio   = parseHHMMToMin(String(op["HORA DE OURO INÍCIO"] || op["HORA DE OURO INICIO"] || '').trim());
  const horaOuroFim      = parseHHMMToMin(String(op["HORA DE OURO FIM"] || op["HORA DE OURO FIM"] || '').trim());
  const dur              = Number(op["TEMPO PARA CADA REUNIÃO (MINUTOS)"]);

  const estaLivre = String(op["ESTÁ RECEBENDO REUNIÃO?"] || op["ESTÁ LIVRE?"] || '').toUpperCase() === "SIM";

  if (!estaLivre) continue;
  if ([inicioHorarioMin, fimHorarioMin, inicioAlmMin, fimAlmMin, dur].some(v => Number.isNaN(v))) continue;
  if (!(dur > 0)) continue;

  const horarios = [];

  // ---------- 1) MANHÃ: desde HORARIO DE INICIO, passo = dur, até que slot termine <= min(horaOuroInicio, inicioAlmMin, fimHorarioMin) ----------
  const morningLimit = Math.min(
    Number.isFinite(horaOuroInicio) ? horaOuroInicio : Infinity,
    Number.isFinite(inicioAlmMin) ? inicioAlmMin : Infinity,
    fimHorarioMin
  );
  if (inicioHorarioMin < morningLimit) {
    for (let t = inicioHorarioMin; t + dur <= morningLimit; t += dur) {
      // se for hoje, só considera slots depois de agora+45
      if (targetDate === todayTZ && t < limiteMin) continue;
      // se colide com busy, pula
      if (collidesWithBusy(email, t, t + dur)) continue;
      horarios.push(`${String(Math.floor(t / 60)).padStart(2, '0')}:${String(t % 60).padStart(2, '0')}`);
    }
  }

  // ---------- 2) PÓS-HORA-DE-OURO: começar em HORA_DE_OURO_FIM e avançar por dur até INÍCIO_ALMOÇO (ou fimHorario) ----------
  if (Number.isFinite(horaOuroFim)) {
    const postGoldLimit = Math.min(Number.isFinite(inicioAlmMin) ? inicioAlmMin : Infinity, fimHorarioMin);
    for (let t = horaOuroFim; t + dur <= postGoldLimit; t += dur) {
      if (targetDate === todayTZ && t < limiteMin) continue;
      if (collidesWithBusy(email, t, t + dur)) continue;
      horarios.push(`${String(Math.floor(t / 60)).padStart(2, '0')}:${String(t % 60).padStart(2, '0')}`);
    }
  }

  // ---------- 3) TARDE: desde FIM_ALMOÇO até HORARIO_FIM ----------
  if (fimAlmMin < fimHorarioMin) {
    for (let t = fimAlmMin; t + dur <= fimHorarioMin; t += dur) {
      if (targetDate === todayTZ && t < limiteMin) continue;
      if (collidesWithBusy(email, t, t + dur)) continue;
      horarios.push(`${String(Math.floor(t / 60)).padStart(2, '0')}:${String(t % 60).padStart(2, '0')}`);
    }
  }

  // Remover duplicatas e ordenar (só por limpeza)
  const unique = Array.from(new Set(horarios)).sort((a, b) => {
    const pa = a.split(':').map(Number), pb = b.split(':').map(Number);
    return pa[0] - pb[0] || pa[1] - pb[1];
  });

  if (unique.length === 0) continue;

  resultado.push({
    nome,
    email: emailRaw,
    horarios: unique,
    duracao_reuniao: dur
  });
}

// retorna no formato esperado pelo n8n
return resultado.map(r => ({ json: r }));

