const closers = $input.all();
const googleEvents = $('Aggregate').first().json.data || [];

function minutosParaHora(minutos) {
  const h = Math.floor(minutos / 60).toString().padStart(2, '0');
  const m = (minutos % 60).toString().padStart(2, '0');
  return `${h}:${m}`;
}

// Converte dateTime do Google para horário de Brasília "HH:mm"
function formatarHoraBrasilia(dateTimeStr) {
  const data = new Date(dateTimeStr);
  const utcMs = data.getTime();
  const brasiliaMs = utcMs - (3 * 60 * 60 * 1000);
  const brasiliaDate = new Date(brasiliaMs);
  const h = brasiliaDate.getUTCHours().toString().padStart(2, '0');
  const m = brasiliaDate.getUTCMinutes().toString().padStart(2, '0');
  return `${h}:${m}`;
}

// Extrai a data "DD/MM" de um dateTime no fuso Brasília (UTC-3)
function extrairDataBrasilia(dateTimeStr) {
  const data = new Date(dateTimeStr);
  const brasiliaMs = data.getTime() - (3 * 60 * 60 * 1000);
  const brasiliaDate = new Date(brasiliaMs);
  const dia = brasiliaDate.getUTCDate().toString().padStart(2, '0');
  const mes = (brasiliaDate.getUTCMonth() + 1).toString().padStart(2, '0');
  return `${dia}/${mes}`;
}

function gerarIntervalosOcupados(closer) {
  const ocupado = [];
  if (closer["INÍCIO ALMOÇO"] && closer["FIM ALMOÇO"]) {
    ocupado.push({ inicio: closer["INÍCIO ALMOÇO"], fim: closer["FIM ALMOÇO"] });
  }
  if (closer["HORA DE OURO INÍCIO"] && closer["HORA DE OURO FIM"]) {
    ocupado.push({ inicio: closer["HORA DE OURO INÍCIO"], fim: closer["HORA DE OURO FIM"] });
  }
  for (let i = 1; i <= 4; i++) {
    const inicio = closer[`Intervalo ${i} inicio`];
    const fim = closer[`Intervalo ${i} fim`];
    if (inicio && fim) ocupado.push({ inicio, fim });
  }
  return ocupado;
}

function removerDuplicados(horarios) {
  const set = new Set();
  return horarios
    .filter(h => h.inicio && h.fim)
    .filter(h => {
      const chave = `${h.inicio}-${h.fim}`;
      if (set.has(chave)) return false;
      set.add(chave);
      return true;
    });
}

// ------------------------------------------------------------
// Gera os próximos 3 dias úteis (hoje + 2), ignorando sab/dom
// Esses são os dias que sempre devem aparecer no output,
// independente de ter eventos no Google Calendar
// ------------------------------------------------------------
function gerarDiasUteis() {
  const dias = [];
  const cursor = new Date();
  while (dias.length < 3) {
    const diaSemana = cursor.getDay();
    if (diaSemana !== 0 && diaSemana !== 6) {
      const dd = cursor.getDate().toString().padStart(2, '0');
      const mm = (cursor.getMonth() + 1).toString().padStart(2, '0');
      dias.push(`${dd}/${mm}`);
    }
    cursor.setDate(cursor.getDate() + 1);
  }
  return dias;
}

const diasValidos = gerarDiasUteis();

const resultado = closers.map(({ json: closer }) => {
  const email = closer.EMAIL;

  // ------------------------------------------------------------
  // Agrupa os eventos do Google por dia (DD/MM)
  // Ignora eventos de dia inteiro (sem dateTime)
  // ------------------------------------------------------------
  const eventosPorDia = {};
  googleEvents
    .filter(ev => ev.start?.dateTime)
    .filter(ev => ev.attendees?.some(a => a.email === email) || ev.creator?.email === email)
    .forEach(ev => {
      const dia = extrairDataBrasilia(ev.start.dateTime);
      if (!eventosPorDia[dia]) eventosPorDia[dia] = [];
      eventosPorDia[dia].push({
        inicio: formatarHoraBrasilia(ev.start.dateTime),
        fim: formatarHoraBrasilia(ev.end.dateTime)
      });
    });

  // Intervalos fixos da planilha (almoço, hora de ouro, intervalos)
  // Esses se aplicam em TODOS os dias
  const horariosPlanilha = gerarIntervalosOcupados(closer);

  // ------------------------------------------------------------
  // Monta o array de dias usando diasValidos como base
  // Garante que dias sem eventos também aparecem (com só os fixos)
  // ------------------------------------------------------------
  const diasComOcupados = diasValidos.map(dia => ({
    dia,
    horarios_ocupados: removerDuplicados([
      ...(eventosPorDia[dia] || []), // eventos do Google (pode ser vazio)
      ...horariosPlanilha             // fixos valem pra todo dia
    ])
  }));

return {
    nome: closer.NOME,
    email,
    horario_inicio: closer["HORARIO DE INICIO"],
    horario_fim: closer["HORARIO FIM"],
    duracao_reuniao: Number(closer["TEMPO PARA CADA REUNIÃO (MINUTOS)"]),
    ultima_reuniao: closer["ÚLTIMA REUNIÃO RECEBIDA"] || "2000-01-01T00:00:00", // 👈
    dias: diasComOcupados
};
});

return resultado.map(item => ({ json: item }));

function horaParaMinutos(hora) {
    if (!hora || hora === "NaN:NaN") return null;
    const partes = String(hora).split(':').map(Number);
    return partes[0] * 60 + partes[1];
}

function minutosParaHora(min) {
    const h = Math.floor(min / 60);
    const m = min % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
}

function getDiaSemana(dataStr) {
    const [dd, mm] = dataStr.split('/').map(Number);
    const ano = new Date().getFullYear();
    const data = new Date(Date.UTC(ano, mm - 1, dd));

    const dias = [
        "Domingo",
        "Segunda",
        "Terça",
        "Quarta",
        "Quinta",
        "Sexta",
        "Sábado"
    ];

    return dias[data.getUTCDay()];
}

function mergeHorarios(horarios) {
    if (!horarios.length) return [];
    horarios.sort((a, b) => a.inicio - b.inicio);
    const result = [horarios[0]];

    for (let i = 1; i < horarios.length; i++) {
        const last = result[result.length - 1];
        const current = horarios[i];

        if (current.inicio <= last.fim) {
            last.fim = Math.max(last.fim, current.fim);
        } else {
            result.push(current);
        }
    }

    return result;
}

function getHorariosLivres(inicioDia, fimDia, duracao, horariosOcupados, minimoMin) {
    const inicioMin = horaParaMinutos(inicioDia);
    const fimMin = horaParaMinutos(fimDia);

    if (inicioMin === null || fimMin === null || !duracao) return [];

    let ocupadosMin = (horariosOcupados || [])
        .map(h => ({
            inicio: horaParaMinutos(h.inicio),
            fim: horaParaMinutos(h.fim)
        }))
        .filter(h => h.inicio !== null && h.fim !== null);

    ocupadosMin = mergeHorarios(ocupadosMin);

    const blocos = [];
    let cursor = inicioMin;

    for (const h of ocupadosMin) {
        if (cursor < h.inicio) {
            blocos.push({ inicio: cursor, fim: h.inicio });
        }
        cursor = Math.max(cursor, h.fim);
    }

    if (cursor < fimMin) {
        blocos.push({ inicio: cursor, fim: fimMin });
    }

    const livres = [];

    for (const bloco of blocos) {
        const primeiroSlot = Math.ceil(bloco.inicio / 15) * 15;
        let s = primeiroSlot;

        while (s + duracao <= bloco.fim) {
            if (minimoMin === undefined || s >= minimoMin) {
                livres.push(minutosParaHora(s));
            }
            s += duracao;
        }
    }

    return livres;
}

// ------------------------------------------------------------
// ETAPA 1: Hora atual de Brasília + próximos 3 dias úteis
// ------------------------------------------------------------

const agora = new Date();
const brasiliaMsOffset = 3 * 60 * 60 * 1000;
const agoraBrasilia = new Date(agora.getTime() - brasiliaMsOffset);

const horaAtualMin =
    agoraBrasilia.getUTCHours() * 60 + agoraBrasilia.getUTCMinutes();

const minimoComAntecedencia = horaAtualMin + 30;

const hojeDD = agoraBrasilia.getUTCDate().toString().padStart(2, '0');
const hojeMM = (agoraBrasilia.getUTCMonth() + 1)
    .toString()
    .padStart(2, '0');

const hojeStr = `${hojeDD}/${hojeMM}`;

const datasPermitidas = [];
const cursorData = new Date(agoraBrasilia);

while (datasPermitidas.length < 3) {
    const diaSemana = cursorData.getUTCDay();

    if (diaSemana !== 0 && diaSemana !== 6) {
        const dd = cursorData.getUTCDate().toString().padStart(2, '0');
        const mm = (cursorData.getUTCMonth() + 1)
            .toString()
            .padStart(2, '0');

        datasPermitidas.push(`${dd}/${mm}`);
    }

    cursorData.setUTCDate(cursorData.getUTCDate() + 1);
}

// ------------------------------------------------------------
// ETAPA 2: Calcula horários livres
// ------------------------------------------------------------

const todosClosers = items.map(item => {
    const op = item.json;

    const horariosFormatados = (op.dias || [])
        .filter(({ dia }) => {
            const diaFormatado = dia.substring(0, 5);
            return datasPermitidas.includes(diaFormatado);
        })
        .flatMap(({ dia, horarios_ocupados }) => {

            const diaFormatado = dia.substring(0, 5);

            const minimo =
                diaFormatado === hojeStr
                    ? minimoComAntecedencia
                    : undefined;

            const livres = getHorariosLivres(
                op.horario_inicio,
                op.horario_fim,
                Number(op.duracao_reuniao),
                horarios_ocupados,
                minimo
            );

            const diaSemana = getDiaSemana(diaFormatado);

            return livres.map(
                hora => `${diaSemana} (${diaFormatado}) às ${hora}`
            );
        });

    return {
        nome: op.nome,
        email: op.email,
        duracao_reuniao: Number(op.duracao_reuniao),
        horarios: horariosFormatados,
        total: horariosFormatados.length
    };
});

// ------------------------------------------------------------
// ETAPA 3: Fallback se não houver horários
// ------------------------------------------------------------

const totalGeral = todosClosers.reduce(
    (soma, c) => soma + c.total,
    0
);

if (totalGeral === 0) {
    return [
        {
            json: {
                fallback: true,
                mensagem:
                    "Nenhum closer possui horários disponíveis no momento. Por favor, informe ao lead que entraremos em contato para agendar manualmente.",
                closers: todosClosers.map(c => ({
                    nome: c.nome,
                    email: c.email,
                    total_horarios_disponiveis: 0
                }))
            }
        }
    ];
}

// ------------------------------------------------------------
// ETAPA 4: prioriza closer com disponibilidade no MESMO DIA (antes das 12h)
// ------------------------------------------------------------

const hora = agoraBrasilia.getUTCHours();
const comHoje = todosClosers.filter(c =>
  c.horarios.some(h => h.includes(`(${hojeStr})`))
);
const pool = (hora < 12 && comHoje.length > 0) ? comHoje : todosClosers;
const melhorCloser = pool.reduce(
  (melhor, atual) => (atual.total > melhor.total ? atual : melhor),
  pool[0]
);



// ------------------------------------------------------------
// ETAPA 5: Retorno final
// ------------------------------------------------------------

return [
    {
        json: {
            fallback: false,
            nome: melhorCloser.nome,
            email: melhorCloser.email,
            duracao_reuniao: melhorCloser.duracao_reuniao,
            total_horarios_disponiveis: melhorCloser.total,
            horarios: melhorCloser.horarios,
            ultima_reuniao: melhorCloser.ultima_reuniao, // 👈 adiciona isso
            outros_closers: todosClosers
                .filter(c => c.email !== melhorCloser.email)
                .map(c => ({
                    nome: c.nome,
                    email: c.email,
                    total_horarios_disponiveis: c.total
                }))
        }
    }
];

function horaParaMinutos(hora) {
    if (!hora || hora === "NaN:NaN") return null;
    const partes = hora.split(':').map(Number);
    if (partes.length !== 2 || partes.some(isNaN)) return null;
    return partes[0] * 60 + partes[1];
}

function minutosParaHora(min) {
    const h = Math.floor(min / 60);
    const m = min % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
}

function getDiaSemana(dataStr) {
    const [dd, mm] = dataStr.split('/').map(Number);
    const ano = new Date().getFullYear();
    const data = new Date(Date.UTC(ano, mm - 1, dd));

    const dias = [
        "Domingo",
        "Segunda",
        "Terça",
        "Quarta",
        "Quinta",
        "Sexta",
        "Sábado"
    ];

    return dias[data.getUTCDay()];
}

function mergeHorarios(horarios) {
    if (!horarios.length) return [];
    horarios.sort((a, b) => a.inicio - b.inicio);
    const result = [horarios[0]];

    for (let i = 1; i < horarios.length; i++) {
        const last = result[result.length - 1];
        const current = horarios[i];

        if (current.inicio <= last.fim) {
            last.fim = Math.max(last.fim, current.fim);
        } else {
            result.push(current);
        }
    }

    return result;
}

function getHorariosLivres(inicioDia, fimDia, duracao, horariosOcupados, minimoMin) {
    const inicioMin = horaParaMinutos(inicioDia);
